import{_ as e,a as i,b as o,c as n,d,e as t,f as r,g as l}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as s,o as c,c as p,a2 as z}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Federacyjny indeks rozproszony","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/federated-distributed-index.md","filePath":"pl-PL/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"pl-PL/Other/federated-distributed-index.md"};function y(w,a,k,h,b,m){return c(),p("div",null,[...a[0]||(a[0]=[z('<h1 id="federacyjny-indeks-rozproszony" tabindex="-1">Federacyjny indeks rozproszony <a class="header-anchor" href="#federacyjny-indeks-rozproszony" aria-label="Permalink to &quot;Federacyjny indeks rozproszony&quot;">​</a></h1><p>Federacyjny indeks rozproszony pozwala wielu stronom ImgBed udostępniać sobie listy plików.</p><p>W prostych słowach:</p><ul><li>Możesz udostępnić wybrane katalogi ze swojej strony innym.</li><li>Możesz dołączyć do innego węzła i zsynchronizować jego udostępnioną listę plików do swojego panelu administracyjnego.</li><li>Pliki federacyjne służą głównie do przeglądania, wyszukiwania i otwierania linków. Nie są ponownie przesyłane do Twojej pamięci.</li></ul><h2 id="gdzie-skonfigurowac" tabindex="-1">Gdzie skonfigurować <a class="header-anchor" href="#gdzie-skonfigurowac" aria-label="Permalink to &quot;Gdzie skonfigurować&quot;">​</a></h2><p>Otwórz:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+e+`" alt="Lokalny węzeł federacji" loading="lazy"></p><p>Strona ma trzy karty:</p><table tabindex="0"><thead><tr><th>Karta</th><th>Cel</th></tr></thead><tbody><tr><td>Local Node</td><td>Włącz własny węzeł, potwierdź publiczną domenę, wybierz katalogi współdzielone i zaktualizuj indeks wychodzący</td></tr><tr><td>Nodes I Joined</td><td>Zarządzaj innymi węzłami ImgBed, do których dołączono</td></tr><tr><td>Nodes Joining Me</td><td>Zarządzaj prośbami innych osób o dołączenie do Twojego węzła</td></tr></tbody></table><h2 id="pierwsza-konfiguracja" tabindex="-1">Pierwsza konfiguracja <a class="header-anchor" href="#pierwsza-konfiguracja" aria-label="Permalink to &quot;Pierwsza konfiguracja&quot;">​</a></h2><ol><li>Otwórz <code>Local Node</code>.</li><li>Włącz <code>Enable</code>.</li><li>Wybierz katalogi do udostępnienia w <code>Sync folders</code>.</li><li>Kliknij <code>Update Outbound Index</code>.</li><li>Jeśli ImgBed wykryje zmianę domeny, potwierdź, że bieżąca domena jest poprawna przed kontynuacją.</li></ol><p>Możesz wybrać wiele katalogów synchronizacji.</p><p>Jeśli lista katalogów synchronizacji jest pusta, udostępniane są wszystkie katalogi.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="publiczna-domena" tabindex="-1">Publiczna domena <a class="header-anchor" href="#publiczna-domena" aria-label="Permalink to &quot;Publiczna domena&quot;">​</a></h3><p>Publiczna domena to URL strony, którego inne węzły używają, aby uzyskać dostęp do Twojego węzła.</p><p>ImgBed wykrywa ją automatycznie. Nie trzeba wpisywać ręcznie. Przy pierwszej aktualizacji indeksu ImgBed zapyta, czy bieżący URL dostępu jest domeną produkcyjną.</p><p>Jeśli później zmienisz domenę, aktualizacja indeksu ponownie poprosi o potwierdzenie.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders określają, które pliki są udostępniane węzłom federacji.</p><p>Na przykład jeśli wybierzesz tylko:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>inne węzły zobaczą tylko pliki w tych dwóch katalogach.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Aktualizuje listę plików, którą inne węzły mogą synchronizować od Ciebie.</p><p>Użyj tego, gdy:</p><ul><li>włączasz federację po raz pierwszy.</li><li>przesyłasz pliki, które chcesz udostępnić.</li><li>zmieniasz katalogi synchronizacji.</li><li>zmieniasz publiczną domenę i musisz ją potwierdzić.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> to miejsce subskrybowania innych węzłów.</p><p><img src="`+i+'" alt="Węzły, do których dołączono" loading="lazy"></p><h3 id="prosba-o-dołaczenie-do-innego-wezła" tabindex="-1">Prośba o dołączenie do innego węzła <a class="header-anchor" href="#prosba-o-dołaczenie-do-innego-wezła" aria-label="Permalink to &quot;Prośba o dołączenie do innego węzła&quot;">​</a></h3><ol><li>Poproś drugiego właściciela o link zaproszenia.</li><li>Wklej go w polu wejściowym.</li><li>Kliknij <code>Request to Join</code>.</li><li>Poczekaj, aż drugi właściciel zatwierdzi prośbę w swoim panelu administracyjnym.</li></ol><p>Po zatwierdzeniu status węzła zmieni się na approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> synchronizuje listy plików z węzłów, do których dołączono.</p><p>Użyj tego, gdy:</p><ul><li>drugi właściciel właśnie zatwierdził Twoją prośbę.</li><li>drugi właściciel informuje, że udostępniona zawartość została zaktualizowana.</li><li>chcesz odświeżyć wszystkie listy plików z dołączonych węzłów.</li></ul><p>Aby zaktualizować tylko jeden węzeł, kliknij <code>Update Index</code> na jego karcie.</p><p><img src="'+o+'" alt="Aktualizacja indeksu" loading="lazy"></p><h3 id="rezygnacja-z-subskrypcji" tabindex="-1">Rezygnacja z subskrypcji <a class="header-anchor" href="#rezygnacja-z-subskrypcji" aria-label="Permalink to &quot;Rezygnacja z subskrypcji&quot;">​</a></h3><p>Jeśli nie chcesz już synchronizować węzła, kliknij <code>Unsubscribe</code>.</p><p>Po rezygnacji indeks federacyjny tego węzła zostanie usunięty z Twojej lokalnej strony.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> to miejsce obsługi próśb od innych.</p><p><img src="'+n+'" alt="Węzły dołączające do mnie" loading="lazy"></p><h3 id="generowanie-linku-zaproszenia" tabindex="-1">Generowanie linku zaproszenia <a class="header-anchor" href="#generowanie-linku-zaproszenia" aria-label="Permalink to &quot;Generowanie linku zaproszenia&quot;">​</a></h3><ol><li>Upewnij się, że lokalny węzeł jest włączony.</li><li>Kliknij <code>Update Outbound Index</code> co najmniej raz, aby ImgBed potwierdził publiczną domenę.</li><li>Otwórz <code>Nodes Joining Me</code>.</li><li>Kliknij <code>Reset Invitation Link</code>.</li><li>Skopiuj link zaproszenia i wyślij go drugiemu właścicielowi.</li></ol><p>Jeśli link zaproszenia jest pusty, publiczna domena zwykle nie została jeszcze potwierdzona. Wróć do <code>Local Node</code> i kliknij <code>Update Outbound Index</code>.</p><h3 id="obsługa-prosb-o-dołaczenie" tabindex="-1">Obsługa próśb o dołączenie <a class="header-anchor" href="#obsługa-prosb-o-dołaczenie" aria-label="Permalink to &quot;Obsługa próśb o dołączenie&quot;">​</a></h3><p>Gdy ktoś wyśle prośbę, pojawi się ona na liście <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Akcja</th><th>Znaczenie</th></tr></thead><tbody><tr><td>Approve</td><td>Pozwala drugiemu węzłowi synchronizować Twoją udostępnioną listę plików</td></tr><tr><td>Reject</td><td>Odrzuca prośbę</td></tr><tr><td>Delete</td><td>Usuwa zakończony rekord</td></tr><tr><td>Check Status</td><td>Sprawdza, czy druga strona nadal utrzymuje tę relację</td></tr></tbody></table><p>Po zatwierdzeniu druga strona nadal musi kliknąć <code>Update Inbound Index</code>, zanim Twoje udostępnione pliki się tam pojawią.</p><p><img src="'+d+'" alt="Zatwierdzanie zaproszonego węzła" loading="lazy"></p><h2 id="wiadomosci" tabindex="-1">Wiadomości <a class="header-anchor" href="#wiadomosci" aria-label="Permalink to &quot;Wiadomości&quot;">​</a></h2><p>Po zatwierdzeniu relacji kliknij <code>Message</code> na karcie węzła.</p><p>Wiadomości służą tylko do komunikacji o relacji federacyjnej. Nie zmieniają plików, tagów, katalogów ani uprawnień.</p><p><img src="'+t+'" alt="Wiadomości" loading="lazy"></p><h2 id="ogladanie-plikow-federacyjnych" tabindex="-1">Oglądanie plików federacyjnych <a class="header-anchor" href="#ogladanie-plikow-federacyjnych" aria-label="Permalink to &quot;Oglądanie plików federacyjnych&quot;">​</a></h2><p>Po zakończeniu synchronizacji wróć do listy plików w panelu administracyjnym.</p><p>Na górze strony przełączaj się między plikami lokalnymi i federacyjnymi. W plikach federacyjnych możesz przeglądać zsynchronizowaną zawartość.</p><p>Pliki federacyjne służą głównie do oglądania, wyszukiwania, podglądu i kopiowania linków. Nie są lokalnymi plikami, więc nie możesz ich przenosić, usuwać, ponownie tagować ani tworzyć ich kopii z własnej strony.</p><p><img src="'+r+'" alt="Pliki federacyjne w panelu administracyjnym" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="dlaczego-prosi-o-ponowne-zgłoszenie-bo-nie-ma-rekordu-relacji" tabindex="-1">Dlaczego prosi o ponowne zgłoszenie, bo nie ma rekordu relacji? <a class="header-anchor" href="#dlaczego-prosi-o-ponowne-zgłoszenie-bo-nie-ma-rekordu-relacji" aria-label="Permalink to &quot;Dlaczego prosi o ponowne zgłoszenie, bo nie ma rekordu relacji?&quot;">​</a></h3><p>Zwykle oznacza to, że druga strona usunęła Cię i skasowała rekord, więc relacja nie może zostać znaleziona. Wyślij nową prośbę o dołączenie.</p><p><img src="'+l+'" alt="Ponowne zgłoszenie bez rekordu relacji" loading="lazy"></p><h3 id="dlaczego-nie-widze-plikow-po-dołaczeniu" tabindex="-1">Dlaczego nie widzę plików po dołączeniu? <a class="header-anchor" href="#dlaczego-nie-widze-plikow-po-dołaczeniu" aria-label="Permalink to &quot;Dlaczego nie widzę plików po dołączeniu?&quot;">​</a></h3><p>Sprawdź:</p><ol><li>Drugi właściciel zatwierdził Twoją prośbę.</li><li>Drugi właściciel kliknął <code>Update Outbound Index</code>.</li><li>Ty kliknąłeś <code>Update Inbound Index</code>.</li><li>Katalogi synchronizacji drugiego właściciela obejmują katalogi, które chce udostępnić.</li></ol><h3 id="co-zrobic-po-wykryciu-zmiany-domeny" tabindex="-1">Co zrobić po wykryciu zmiany domeny? <a class="header-anchor" href="#co-zrobic-po-wykryciu-zmiany-domeny" aria-label="Permalink to &quot;Co zrobić po wykryciu zmiany domeny?&quot;">​</a></h3><p>Jeśli aktualnie otwierasz panel administracyjny przez domenę produkcyjną, potwierdź i kontynuuj.</p><p>Jeśli używasz tymczasowego adresu, anuluj, otwórz panel przez domenę produkcyjną i spróbuj ponownie.</p><h3 id="co-oznacza-pusta-lista-sync-folder" tabindex="-1">Co oznacza pusta lista Sync Folder? <a class="header-anchor" href="#co-oznacza-pusta-lista-sync-folder" aria-label="Permalink to &quot;Co oznacza pusta lista Sync Folder?&quot;">​</a></h3><p>Pusta lista Sync Folder oznacza, że udostępniane są wszystkie katalogi.</p><p>Aby udostępnić tylko wybrane katalogi, zaznacz je ręcznie.</p><h3 id="roznica-miedzy-aktualizacja-outbound-i-inbound" tabindex="-1">Różnica między aktualizacją outbound i inbound <a class="header-anchor" href="#roznica-miedzy-aktualizacja-outbound-i-inbound" aria-label="Permalink to &quot;Różnica między aktualizacją outbound i inbound&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Przycisk</th><th>Proste znaczenie</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Aktualizuje to, co inni mogą synchronizować ode mnie</td></tr><tr><td>Update Inbound Index</td><td>Aktualizuje to, co ja zsynchronizowałem od innych</td></tr></tbody></table>',78)])])}const x=s(u,[["render",y]]);export{f as __pageData,x as default};
